        op = Op(self, "GatherBlockQuantized", schema)
        return op(
            *self._prepare_inputs(schema, data, indices, scales, zero_points),
            bits=bits,
            block_size=block_size,
            gather_axis=gather_axis,
            quantize_axis=quantize_axis,
        )

