    def UnfoldTensor(
        self, input: T_UnfoldTensor, *, size: int, dim: int = -1, step: int = 1
    ) -> T_UnfoldTensor:
        r"""[🌐 com.microsoft::UnfoldTensor(1)](https://github.com/microsoft/onnxruntime/blob/main/docs/ContribOperators.md#com.microsoft.unfoldtensor "Online Documentation")

        Returns a tensor which contains all slices of size `size` from input tensor in the dimension `dim`. Step between two slices is given by `step`. If `sizedim` is the size of dimension `dim` for input tensor, the size of dimension `dim` in the returned tensor will be `(sizedim - size) / step + 1`. An additional dimension of size `size` is appended in the returned tensor.

        Args:
            input: input tensor

            size: specify the size

            dim: specify the dimension to unfold

            step: specify the step.
        """
        schema = get_schema("UnfoldTensor", 1, "com.microsoft")
        op = Op(self, "UnfoldTensor", schema)
        return op(*self._prepare_inputs(schema, input), size=size, dim=dim, step=step)

