    def WhisperBeamSearch(
        self,
        input_ids: F_WhisperBeamSearch,
        max_length: I_WhisperBeamSearch,
        min_length: I_WhisperBeamSearch | None,
        num_beams: I_WhisperBeamSearch,
        num_return_sequences: I_WhisperBeamSearch,
        length_penalty: T_WhisperBeamSearch | None = None,
        repetition_penalty: T_WhisperBeamSearch | None = None,
        vocab_mask: M_WhisperBeamSearch | None = None,
        prefix_vocab_mask: M_WhisperBeamSearch | None = None,
        attention_mask: I_WhisperBeamSearch | None = None,
        decoder_input_ids: I_WhisperBeamSearch | None = None,
        logits_processor: I_WhisperBeamSearch | None = None,
        cross_qk_layer_head: I_WhisperBeamSearch | None = None,
        extra_decoding_ids: I_WhisperBeamSearch | None = None,
        temperature: T_WhisperBeamSearch | None = None,
        *,
        decoder: GraphProto,
        eos_token_id: int,
        pad_token_id: int,
        beginning_timestamp_token_id: int | None = None,
        decoder_output_cross_qk: int | None = None,
        decoder_start_token_id: int = -1,
        early_stopping: int = 0,
        encoder: GraphProto | None = None,
        init_decoder: GraphProto | None = None,
        model_type: int = 2,
        no_repeat_ngram_size: int = 0,
        no_speech_token_id: int | None = None,
        no_timestamps_token_id: int | None = None,
        start_of_lm_token_id: int | None = None,
        transcribe_token_id: int | None = None,
        translate_token_id: int | None = None,
        vocab_size: int = -1,
    ) -> tuple[
        I_WhisperBeamSearch,
        T_WhisperBeamSearch,
        T_WhisperBeamSearch,
        V_WhisperBeamSearch,
        T_WhisperBeamSearch,
    ]:
        r"""[🌐 com.microsoft::WhisperBeamSearch(1)](https://github.com/microsoft/onnxruntime/blob/main/docs/ContribOperators.md#com.microsoft.whisperbeamsearch "Online Documentation")

        Beam Search for whisper model, especially with cross_qk features etc.

        Args:
            input_ids: The sequence used as a prompt for the generation in the encoder
                subgraph. Shape is (batch_size, sequence_length)

            max_length: The maximum length of the sequence to be generated. Shape is (1)

            min_length: (optional) The minimum length below which the score of
                eos_token_id is set to -Inf. Shape is (1)

            num_beams: Number of beams for beam search. 1 means no beam search. Shape is
                (1)

            num_return_sequences: The number of returned sequences in the batch. Shape
                is (1)

            length_penalty: (optional) Exponential penalty to the length. Default value
                1.0 means no penalty. Value > 1.0 encourages longer sequences, while
                values < 1.0 produces shorter sequences. Shape is (1,)

            repetition_penalty: (optional) The parameter for repetition penalty. Default
                value 1.0 means no penalty. Accepts value > 0.0. Shape is (1)

            vocab_mask: (optional) Mask of vocabulary. Words that masked with 0 are not
                allowed to be generated, and 1 is allowed. Shape is (vocab_size)

            prefix_vocab_mask: (optional) Mask of vocabulary for first step. Words that
                masked with 0 are not allowed to be generated, and 1 is allowed. Shape
                is (batch_size, vocab_size)

            attention_mask: (optional) Custom attention mask. Shape is (batch_size,
                sequence_length)

            decoder_input_ids: (optional) The forced input id sequence for the decoder
                subgraph. Shape is (batch_size, initial_sequence_length)

            logits_processor: (optional) Specific logits processor for different types
                of beamsearch models. Default value 0 means no specific logit processor.
                Accepts value >= 0. Shape is (1)

            cross_qk_layer_head: (optional) Only keep this list of (layer, head) of QK
                in the final cross_qk output when use_cross_qk is set. Default collect
                all its shape is (number of (layer, head) to keep, 2), i.e.,
                [[layer_id1, head_id1], [layer_id2, head_id2]......]

            extra_decoding_ids: (optional) Part of the decoder_input_ids that we need
                cross qk for it. it is of shape (batch_size, extra_decoding_ids_len).In
                such case, we should remove this from the tail of the decoder_input_ids,
                and put it here. ids < 0 in it (for multiple batch) are treated as stop
                of the extra_decoding_ids for corresponding batch.

            temperature: (optional) Temperature value to apply to logits processing
                during this execution's decoding. Shape is (1)

            decoder: Decoder subgraph to execute in a loop.

            eos_token_id: The id of the end-of-sequence token

            pad_token_id: The id of the padding token

            beginning_timestamp_token_id: The id of the first timestamp

            decoder_output_cross_qk: If nozero, decoder subgraph contains output Q*K
                from cross attentions. Default 0.

            decoder_start_token_id: The id of the token that indicates decoding starts
                (i.e. the start of transcription token id)

            early_stopping: early stop or not

            encoder: The subgraph for initialization of encoder and decoder. It will be
                called once before decoder subgraph.

            init_decoder: The subgraph for the first decoding run. It will be called
                once before `decoder` subgraph. This is relevant only for the GPT2
                model. If this attribute is missing, the `decoder` subgraph will be used
                for all decoding runs

            model_type: Must be 2 for whisper

            no_repeat_ngram_size: no repeat ngrams size

            no_speech_token_id: The token in whisper model that marks all sequence
                empty. With this model, whisper could output no_speech_prob after.
                Default -1.

            no_timestamps_token_id: The id of the token that indicates no timestamps

            start_of_lm_token_id: The id of the token that indicates LM starts

            transcribe_token_id: The id of the transcribe task

            translate_token_id: The id of the translate task

            vocab_size: Size of the vocabulary. If not provided, it will be inferred
                from the decoder subgraph's output shape
        """
        schema = get_schema("WhisperBeamSearch", 1, "com.microsoft")
        op = Op(self, "WhisperBeamSearch", schema)
        return op(
            *self._prepare_inputs(
                schema,
                input_ids,
                max_length,
                min_length,
                num_beams,
                num_return_sequences,
                length_penalty,
                repetition_penalty,
                vocab_mask,
                prefix_vocab_mask,
                attention_mask,
                decoder_input_ids,
                logits_processor,
                cross_qk_layer_head,
                extra_decoding_ids,
                temperature,
            ),
            decoder=decoder,
            eos_token_id=eos_token_id,
            pad_token_id=pad_token_id,
            beginning_timestamp_token_id=beginning_timestamp_token_id,
            decoder_output_cross_qk=decoder_output_cross_qk,
            decoder_start_token_id=decoder_start_token_id,
            early_stopping=early_stopping,
            encoder=encoder,
            init_decoder=init_decoder,
            model_type=model_type,
            no_repeat_ngram_size=no_repeat_ngram_size,
            no_speech_token_id=no_speech_token_id,
            no_timestamps_token_id=no_timestamps_token_id,
            start_of_lm_token_id=start_of_lm_token_id,
            transcribe_token_id=transcribe_token_id,
            translate_token_id=translate_token_id,
            vocab_size=vocab_size,
        )

